namespace sv_2799ab90e6164b2b814885e5d0f9596c.Services;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);
public record NotificationPrefs(bool EmailNotifications, bool PushNotifications, bool WeeklyDigest, List<string> MutedChannels);
public record SecuritySettings(bool TwoFactorEnabled, DateTime? LastPasswordChange, List<ActiveSession> Sessions);
public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);
public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@namespace sv_2799ab90e6164b2b814885e5d0f9596c.Components.Settings

<nav class="settings-sidebar">
    <h5 class="sidebar-title">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link @(ActiveSection == section.Key ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section.Key)">
                    <span class="section-icon">@section.Icon</span>
                    @section.Label
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter, EditorRequired] public string ActiveSection { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> OnSectionChanged { get; set; }

    private record SectionInfo(string Key, string Label, string Icon);

    private static readonly SectionInfo[] Sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨")
    ];
}

.settings-sidebar {
    min-width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.5rem 0;
    height: 100%;
}

.sidebar-title {
    padding: 0 1.25rem 1rem;
    margin: 0;
    font-weight: 600;
    color: #495057;
    border-bottom: 1px solid #dee2e6;
}

.nav-link {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.75rem 1.25rem;
    color: #495057;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    font-size: 0.95rem;
    cursor: pointer;
    transition: background-color 0.15s, color 0.15s;
    border-left: 3px solid transparent;
}

.nav-link:hover {
    background: #e9ecef;
    color: #212529;
}

.nav-link.active {
    background: #e7f1ff;
    color: #0d6efd;
    font-weight: 600;
    border-left-color: #0d6efd;
}

.section-icon {
    font-size: 1.1rem;
}

@namespace sv_2799ab90e6164b2b814885e5d0f9596c.Components.Settings
@using sv_2799ab90e6164b2b814885e5d0f9596c.Services
@inject ISettingsService SettingsService

<div class="profile-section">
    <h4>Profile Settings</h4>
    <hr />

    @if (loading)
    {
        <div class="text-center py-4">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label class="form-label fw-semibold">Display Name</label>
                    <input type="text" class="form-control" @bind="displayName" />
                </div>

                <div class="mb-3">
                    <label class="form-label fw-semibold">Email</label>
                    <input type="email" class="form-control" @bind="email" />
                </div>

                <div class="mb-3">
                    <label class="form-label fw-semibold">Bio</label>
                    <textarea class="form-control" rows="4" @bind="bio"></textarea>
                </div>
            </div>

            <div class="col-md-4">
                <div class="avatar-preview-area">
                    <label class="form-label fw-semibold">Avatar Preview</label>
                    <div class="avatar-frame">
                        @if (!string.IsNullOrWhiteSpace(avatarUrl))
                        {
                            <img src="@avatarUrl" alt="Avatar" class="avatar-image" />
                        }
                        else
                        {
                            <div class="avatar-placeholder">👤</div>
                        }
                    </div>
                    <div class="mt-2">
                        <label class="form-label text-muted small">Avatar URL</label>
                        <input type="url" class="form-control form-control-sm" @bind="avatarUrl" />
                    </div>
                </div>
            </div>
        </div>

        <div class="d-flex gap-2 mt-3">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@saving">
                @if (saving)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@saving">
                Discard Changes
            </button>
        </div>

        @if (showSuccess)
        {
            <div class="alert alert-success mt-3 d-flex align-items-center" role="alert">
                <span class="me-2">✅</span> Profile saved successfully!
            </div>
        }

        @if (errorMessage is not null)
        {
            <div class="alert alert-danger mt-3" role="alert">@errorMessage</div>
        }
    }
</div>

@code {
    private bool loading = true;
    private bool saving;
    private bool showSuccess;
    private string? errorMessage;

    private string displayName = "";
    private string email = "";
    private string bio = "";
    private string avatarUrl = "";

    private UserProfile? savedProfile;

    protected override async Task OnInitializedAsync()
    {
        await LoadProfileAsync();
    }

    private async Task LoadProfileAsync()
    {
        loading = true;
        try
        {
            savedProfile = await SettingsService.GetProfileAsync();
            ApplyProfile(savedProfile);
        }
        finally
        {
            loading = false;
        }
    }

    private void ApplyProfile(UserProfile profile)
    {
        displayName = profile.DisplayName;
        email = profile.Email;
        bio = profile.Bio;
        avatarUrl = profile.AvatarUrl;
    }

    private async Task SaveAsync()
    {
        saving = true;
        showSuccess = false;
        errorMessage = null;
        try
        {
            var updated = new UserProfile(displayName, email, avatarUrl, bio);
            await SettingsService.SaveProfileAsync(updated);
            savedProfile = updated;
            showSuccess = true;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to save profile: {ex.Message}";
        }
        finally
        {
            saving = false;
        }
    }

    private void Discard()
    {
        if (savedProfile is not null)
        {
            ApplyProfile(savedProfile);
        }
        showSuccess = false;
        errorMessage = null;
    }
}

.avatar-preview-area {
    text-align: center;
}

.avatar-frame {
    width: 120px;
    height: 120px;
    border-radius: 50%;
    border: 3px solid #dee2e6;
    overflow: hidden;
    display: flex;
    align-items: center;
    justify-content: center;
    margin: 0 auto;
    background: #f8f9fa;
}

.avatar-image {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-placeholder {
    font-size: 3rem;
    color: #adb5bd;
}

@namespace sv_2799ab90e6164b2b814885e5d0f9596c.Components.Settings
@using sv_2799ab90e6164b2b814885e5d0f9596c.Services
@inject ISettingsService SettingsService

<div class="notifications-section">
    <h4>Notification Preferences</h4>
    <hr />

    @if (loading)
    {
        <div class="text-center py-4">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="mb-4">
            <h6 class="fw-semibold mb-3">General</h6>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch"
                       id="emailNotif" @bind="emailNotifications" />
                <label class="form-check-label" for="emailNotif">
                    Email Notifications
                    <small class="d-block text-muted">Receive notifications via email</small>
                </label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch"
                       id="pushNotif" @bind="pushNotifications" />
                <label class="form-check-label" for="pushNotif">
                    Push Notifications
                    <small class="d-block text-muted">Receive push notifications in your browser</small>
                </label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch"
                       id="weeklyDigest" @bind="weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">
                    Weekly Digest
                    <small class="d-block text-muted">Get a weekly summary of activity</small>
                </label>
            </div>
        </div>

        <div class="mb-4">
            <h6 class="fw-semibold mb-3">Muted Channels</h6>
            @if (allChannels.Count == 0)
            {
                <p class="text-muted">No channels available.</p>
            }
            else
            {
                <div class="channel-list">
                    @foreach (var channel in allChannels)
                    {
                        var ch = channel;
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="checkbox"
                                   id="@($"ch-{ch}")"
                                   checked="@mutedChannels.Contains(ch)"
                                   @onchange="e => ToggleMute(ch, (bool)(e.Value ?? false))" />
                            <label class="form-check-label" for="@($"ch-{ch}")">@ch</label>
                        </div>
                    }
                </div>
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@saving">
            @if (saving)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Save Preferences
        </button>

        @if (showSuccess)
        {
            <div class="alert alert-success mt-3 d-flex align-items-center" role="alert">
                <span class="me-2">✅</span> Notification preferences saved!
            </div>
        }

        @if (errorMessage is not null)
        {
            <div class="alert alert-danger mt-3" role="alert">@errorMessage</div>
        }
    }
</div>

@code {
    private bool loading = true;
    private bool saving;
    private bool showSuccess;
    private string? errorMessage;

    private bool emailNotifications;
    private bool pushNotifications;
    private bool weeklyDigest;
    private HashSet<string> mutedChannels = new();

    // Channels the user can mute — seeded from the saved muted list
    private List<string> allChannels = new();

    protected override async Task OnInitializedAsync()
    {
        loading = true;
        try
        {
            var prefs = await SettingsService.GetNotificationPrefsAsync();
            emailNotifications = prefs.EmailNotifications;
            pushNotifications = prefs.PushNotifications;
            weeklyDigest = prefs.WeeklyDigest;
            allChannels = new List<string>(prefs.MutedChannels ?? []);
            mutedChannels = new HashSet<string>(allChannels);
        }
        finally
        {
            loading = false;
        }
    }

    private void ToggleMute(string channel, bool isMuted)
    {
        if (isMuted)
            mutedChannels.Add(channel);
        else
            mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        saving = true;
        showSuccess = false;
        errorMessage = null;
        try
        {
            var prefs = new NotificationPrefs(
                emailNotifications,
                pushNotifications,
                weeklyDigest,
                mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            showSuccess = true;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to save preferences: {ex.Message}";
        }
        finally
        {
            saving = false;
        }
    }
}

@namespace sv_2799ab90e6164b2b814885e5d0f9596c.Components.Settings
@using sv_2799ab90e6164b2b814885e5d0f9596c.Services
@inject ISettingsService SettingsService

<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center"
         style="cursor: pointer;" @onclick="() => expanded = !expanded">
        <h6 class="mb-0 fw-semibold">🔑 Change Password</h6>
        <span class="expand-icon">@(expanded ? "▲" : "▼")</span>
    </div>

    @if (expanded)
    {
        <div class="card-body">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="confirmPassword" />
            </div>

            @if (validationError is not null)
            {
                <div class="alert alert-warning py-2" role="alert">@validationError</div>
            }

            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@updating">
                @if (updating)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Update Password
            </button>

            @if (showSuccess)
            {
                <div class="alert alert-success mt-3 py-2" role="alert">
                    ✅ Password updated successfully!
                </div>
            }

            @if (errorMessage is not null)
            {
                <div class="alert alert-danger mt-3 py-2" role="alert">@errorMessage</div>
            }
        </div>
    }
</div>

@code {
    private bool expanded;
    private bool updating;
    private bool showSuccess;
    private string? validationError;
    private string? errorMessage;

    private string currentPassword = "";
    private string newPassword = "";
    private string confirmPassword = "";

    private async Task UpdatePasswordAsync()
    {
        validationError = null;
        errorMessage = null;
        showSuccess = false;

        if (string.IsNullOrWhiteSpace(currentPassword))
        {
            validationError = "Current password is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(newPassword))
        {
            validationError = "New password is required.";
            return;
        }
        if (newPassword != confirmPassword)
        {
            validationError = "New password and confirmation do not match.";
            return;
        }

        updating = true;
        try
        {
            await SettingsService.ChangePasswordAsync(currentPassword, newPassword);
            showSuccess = true;
            currentPassword = "";
            newPassword = "";
            confirmPassword = "";
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to change password: {ex.Message}";
        }
        finally
        {
            updating = false;
        }
    }
}

