                <input type="password" class="form-control" @bind="newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="confirmPassword" />
            </div>

            @if (validationError is not null)
            {
                <div class="alert alert-warning py-2" role="alert">@validationError</div>
            }

            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@updating">
                @if (updating)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Update Password
            </button>

            @if (showSuccess)
            {
                <div class="alert alert-success mt-3 py-2" role="alert">
                    ✅ Password updated successfully!
                </div>
            }

