@code {
    private bool expanded;
    private bool updating;
    private bool showSuccess;
    private string? validationError;
    private string? errorMessage;

    private string currentPassword = "";
    private string newPassword = "";
    private string confirmPassword = "";

    private async Task UpdatePasswordAsync()
    {
        validationError = null;
        errorMessage = null;
        showSuccess = false;

        if (string.IsNullOrWhiteSpace(currentPassword))
        {
            validationError = "Current password is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(newPassword))
        {
            validationError = "New password is required.";
            return;
        }
        if (newPassword != confirmPassword)
        {
            validationError = "New password and confirmation do not match.";
            return;
        }

        updating = true;
        try
        {
            await SettingsService.ChangePasswordAsync(currentPassword, newPassword);
            showSuccess = true;
            currentPassword = "";
            newPassword = "";
            confirmPassword = "";
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to change password: {ex.Message}";
        }
        finally
        {
            updating = false;
        }
    }
}

