{"path": "/tmp/sv-2799ab90e6164b2b814885e5d0f9596c/Components/Settings/ProfileSection.razor", "file_text": "@namespace sv_2799ab90e6164b2b814885e5d0f9596c.Components.Settings
@using sv_2799ab90e6164b2b814885e5d0f9596c.Services
@inject ISettingsService SettingsService

<div class="profile-section">
    <h4>Profile Settings</h4>
    <hr />

    @if (loading)
    {
        <div class="text-center py-4">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label class="form-label fw-semibold">Display Name</label>
                    <input type="text" class="form-control" @bind="displayName" />
                </div>

                <div class="mb-3">
                    <label class="form-label fw-semibold">Email</label>
                    <input type="email" class="form-control" @bind="email" />
                </div>

                <div class="mb-3">
                    <label class="form-label fw-semibold">Bio</label>
                    <textarea class="form-control" rows="4" @bind="bio"></textarea>
                </div>
            </div>

            <div class="col-md-4">
                <div class="avatar-preview-area">
                    <label class="form-label fw-semibold">Avatar Preview</label>
                    <div class="avatar-frame">
                        @if (!string.IsNullOrWhiteSpace(avatarUrl))
                        {
                            <img src="@avatarUrl" alt="Avatar" class="avatar-image" />
                        }
                        else
                        {
                            <div class="avatar-placeholder">👤</div>
                        }
                    </div>
                    <div class="mt-2">
                        <label class="form-label text-muted small">Avatar URL</label>
                        <input type="url" class="form-control form-control-sm" @bind="avatarUrl" />
                    </div>
                </div>
            </div>
        </div>

        <div class="d-flex gap-2 mt-3">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@saving">
                @if (saving)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@saving">
                Discard Changes
            </button>
        </div>

        @if (showSuccess)
        {
            <div class="alert alert-success mt-3 d-flex align-items-center" role="alert">
                <span class="me-2">✅</span> Profile saved successfully!
            </div>
        }

        @if (errorMessage is not null)
        {
            <div class="alert alert-danger mt-3" role="alert">@errorMessage</div>
        }
    }
</div>

@code {
    private bool loading = true;
    private bool saving;
    private bool showSuccess;
    private string? errorMessage;

    private string displayName = "";
    private string email = "";
    private string bio = "";
    private string avatarUrl = "";

    private UserProfile? savedProfile;

    protected override async Task OnInitializedAsync()
    {
        await LoadProfileAsync();
    }

    private async Task LoadProfileAsync()
    {
        loading = true;
        try
        {
            savedProfile = await SettingsService.GetProfileAsync();
            ApplyProfile(savedProfile);
        }
        finally
        {
            loading = false;
        }
    }

    private void ApplyProfile(UserProfile profile)
    {
        displayName = profile.DisplayName;
        email = profile.Email;
        bio = profile.Bio;
        avatarUrl = profile.AvatarUrl;
    }

    private async Task SaveAsync()
    {
        saving = true;
        showSuccess = false;
        errorMessage = null;
        try
        {
            var updated = new UserProfile(displayName, email, avatarUrl, bio);
            await SettingsService.SaveProfileAsync(updated);
            savedProfile = updated;
            showSuccess = true;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to save profile: {ex.Message}";
        }
        finally
        {
            saving = false;
        }
    }

    private void Discard()
    {
        if (savedProfile is not null)
        {
            ApplyProfile(savedProfile);
        }
        showSuccess = false;
        errorMessage = null;
    }
}
"}

