{"path": "/tmp/sv-2799ab90e6164b2b814885e5d0f9596c/Components/Settings/NotificationsSection.razor", "file_text": "@namespace sv_2799ab90e6164b2b814885e5d0f9596c.Components.Settings
@using sv_2799ab90e6164b2b814885e5d0f9596c.Services
@inject ISettingsService SettingsService

<div class="notifications-section">
    <h4>Notification Preferences</h4>
    <hr />

    @if (loading)
    {
        <div class="text-center py-4">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="mb-4">
            <h6 class="fw-semibold mb-3">General</h6>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch"
                       id="emailNotif" @bind="emailNotifications" />
                <label class="form-check-label" for="emailNotif">
                    Email Notifications
                    <small class="d-block text-muted">Receive notifications via email</small>
                </label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch"
                       id="pushNotif" @bind="pushNotifications" />
                <label class="form-check-label" for="pushNotif">
                    Push Notifications
                    <small class="d-block text-muted">Receive push notifications in your browser</small>
                </label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch"
                       id="weeklyDigest" @bind="weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">
                    Weekly Digest
                    <small class="d-block text-muted">Get a weekly summary of activity</small>
                </label>
            </div>
        </div>

        <div class="mb-4">
            <h6 class="fw-semibold mb-3">Muted Channels</h6>
            @if (allChannels.Count == 0)
            {
                <p class="text-muted">No channels available.</p>
            }
            else
            {
                <div class="channel-list">
                    @foreach (var channel in allChannels)
                    {
                        var ch = channel;
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="checkbox"
                                   id="@($"ch-{ch}")"
                                   checked="@mutedChannels.Contains(ch)"
                                   @onchange="e => ToggleMute(ch, (bool)(e.Value ?? false))" />
                            <label class="form-check-label" for="@($"ch-{ch}")">@ch</label>
                        </div>
                    }
                </div>
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@saving">
            @if (saving)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Save Preferences
        </button>

        @if (showSuccess)
        {
            <div class="alert alert-success mt-3 d-flex align-items-center" role="alert">
                <span class="me-2">✅</span> Notification preferences saved!
            </div>
        }

        @if (errorMessage is not null)
        {
            <div class="alert alert-danger mt-3" role="alert">@errorMessage</div>
        }
    }
</div>

@code {
    private bool loading = true;
    private bool saving;
    private bool showSuccess;
    private string? errorMessage;

    private bool emailNotifications;
    private bool pushNotifications;
    private bool weeklyDigest;
    private HashSet<string> mutedChannels = new();

    // Channels the user can mute — seeded from the saved muted list
    private List<string> allChannels = new();

    protected override async Task OnInitializedAsync()
    {
        loading = true;
        try
        {
            var prefs = await SettingsService.GetNotificationPrefsAsync();
            emailNotifications = prefs.EmailNotifications;
            pushNotifications = prefs.PushNotifications;
            weeklyDigest = prefs.WeeklyDigest;
            allChannels = new List<string>(prefs.MutedChannels ?? []);
            mutedChannels = new HashSet<string>(allChannels);
        }
        finally
        {
            loading = false;
        }
    }

    private void ToggleMute(string channel, bool isMuted)
    {
        if (isMuted)
            mutedChannels.Add(channel);
        else
            mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        saving = true;
        showSuccess = false;
        errorMessage = null;
        try
        {
            var prefs = new NotificationPrefs(
                emailNotifications,
                pushNotifications,
                weeklyDigest,
                mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            showSuccess = true;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to save preferences: {ex.Message}";
        }
        finally
        {
            saving = false;
        }
    }
}
"}

{"path": "/tmp/sv-2799ab90e6164b2b814885e5d0f9596c/Components/Settings/ChangePasswordPanel.razor", "file_text": "@namespace sv_2799ab90e6164b2b814885e5d0f9596c.Components.Settings
@using sv_2799ab90e6164b2b814885e5d0f9596c.Services
@inject ISettingsService SettingsService

<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center"
         style="cursor: pointer;" @onclick="() => expanded = !expanded">
        <h6 class="mb-0 fw-semibold">🔑 Change Password</h6>
        <span class="expand-icon">@(expanded ? "▲" : "▼")</span>
    </div>

    @if (expanded)
    {
        <div class="card-body">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="confirmPassword" />
            </div>

            @if (validationError is not null)
            {
                <div class="alert alert-warning py-2" role="alert">@validationError</div>
            }

            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@updating">
                @if (updating)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Update Password
            </button>

            @if (showSuccess)
            {
                <div class="alert alert-success mt-3 py-2" role="alert">
                    ✅ Password updated successfully!
                </div>
            }

            @if (errorMessage is not null)
            {
                <div class="alert alert-danger mt-3 py-2" role="alert">@errorMessage</div>
            }
        </div>
    }
</div>

@code {
    private bool expanded;
    private bool updating;
    private bool showSuccess;
    private string? validationError;
    private string? errorMessage;

    private string currentPassword = "";
    private string newPassword = "";
    private string confirmPassword = "";

    private async Task UpdatePasswordAsync()
    {
        validationError = null;
        errorMessage = null;
        showSuccess = false;

        if (string.IsNullOrWhiteSpace(currentPassword))
        {
            validationError = "Current password is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(newPassword))
        {
            validationError = "New password is required.";
            return;
        }
        if (newPassword != confirmPassword)
        {
            validationError = "New password and confirmation do not match.";
            return;
        }

        updating = true;
        try
        {
            await SettingsService.ChangePasswordAsync(currentPassword, newPassword);
            showSuccess = true;
            currentPassword = "";
            newPassword = "";
            confirmPassword = "";
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to change password: {ex.Message}";
        }
        finally
        {
            updating = false;
        }
    }
}
"}

{"path": "/tmp/sv-2799ab90e6164b2b814885e5d0f9596c/Components/Settings/ActiveSessionsTable.razor", "file_text": "@namespace sv_2799ab90e6164b2b814885e5d0f9596c.Components.Settings
@using sv_2799ab90e6164b2b814885e5d0f9596c.Services

<div class="mb-4">
    <h6 class="fw-semibold mb-3">Active Sessions</h6>

    @if (Sessions.Count == 0)
    {
        <p class="text-muted">No active sessions.</p>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-hover align-middle">
                <thead class="table-light">
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th class="text-end">Action</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@session.LastActive.ToString("g")</td>
                            <td class="text-end">
                                @if (session == Sessions.FirstOrDefault())
                                {
                                    <span class="badge bg-success">Current</span>
                                }
                                else if (confirmingSessionId == session.Id)
                                {
                                    <span class="me-2 text-danger small">Revoke this session?</span>
                                    <button class="btn btn-danger btn-sm me-1"
                                            @onclick="() => ConfirmRevokeAsync(session.Id)"
                                            disabled="@revoking">
                                        @if (revoking)
                                        {
                                            <span class="spinner-border spinner-border-sm" role="status"></span>
                                        }
                                        else
                                        {
                                            <text>Yes</text>
                                        }
                                    </button>
                                    <button class="btn btn-outline-secondary btn-sm"
                                            @onclick="() => confirmingSessionId = null">
                                        No
                                    </button>
                                }
                                else
                                {
                                    <button class="btn btn-outline-danger btn-sm"
                                            @onclick="() => confirmingSessionId = session.Id">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }

    @if (errorMessage is not null)
    {
        <div class="alert alert-danger py-2" role="alert">@errorMessage</div>
    }
</div>

@code {
    [Parameter, EditorRequired] public List<ActiveSession> Sessions { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<string> OnSessionRevoked { get; set; }

    private string? confirmingSessionId;
    private bool revoking;
    private string? errorMessage;

    private async Task ConfirmRevokeAsync(string sessionId)
    {
        revoking = true;
        errorMessage = null;
        try
        {
            await OnSessionRevoked.InvokeAsync(sessionId);
            confirmingSessionId = null;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to revoke session: {ex.Message}";
        }
        finally
        {
            revoking = false;
        }
    }
}
"}

{"path": "/tmp/sv-2799ab90e6164b2b814885e5d0f9596c/Components/Settings/SecuritySection.razor", "file_text": "@namespace sv_2799ab90e6164b2b814885e5d0f9596c.Components.Settings
@using sv_2799ab90e6164b2b814885e5d0f9596c.Services
@inject ISettingsService SettingsService

<div class="security-section">
    <h4>Security Settings</h4>
    <hr />

    @if (loading)
    {
        <div class="text-center py-4">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <ChangePasswordPanel />

        <div class="card mb-4">
            <div class="card-body">
                <div class="d-flex justify-content-between align-items-center">
                    <div>
                        <h6 class="fw-semibold mb-1">Two-Factor Authentication</h6>
                        <p class="text-muted mb-0 small">
                            Add an extra layer of security to your account.
                        </p>
                    </div>
                    <div class="d-flex align-items-center gap-2">
                        <span class="badge @(twoFactorEnabled ? "bg-success" : "bg-secondary")">
                            @(twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                        <div class="form-check form-switch mb-0">
                            <input class="form-check-input" type="checkbox" role="switch"
                                   id="twoFactor" @bind="twoFactorEnabled" />
                        </div>
                    </div>
                </div>
            </div>
        </div>

        @if (lastPasswordChange.HasValue)
        {
            <p class="text-muted small mb-4">
                🕒 Last password change: @lastPasswordChange.Value.ToString("f")
            </p>
        }

        <ActiveSessionsTable Sessions="sessions" OnSessionRevoked="RevokeSessionAsync" />
    }
</div>

@code {
    private bool loading = true;
    private bool twoFactorEnabled;
    private DateTime? lastPasswordChange;
    private List<ActiveSession> sessions = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        loading = true;
        try
        {
            var settings = await SettingsService.GetSecuritySettingsAsync();
            twoFactorEnabled = settings.TwoFactorEnabled;
            lastPasswordChange = settings.LastPasswordChange;
            sessions = settings.Sessions ?? new();
        }
        finally
        {
            loading = false;
        }
    }

    private async Task RevokeSessionAsync(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        sessions.RemoveAll(s => s.Id == sessionId);
    }
}
"}

