{"path": "/tmp/sv-2799ab90e6164b2b814885e5d0f9596c/Components/Settings/AppearanceSection.razor", "file_text": "@namespace sv_2799ab90e6164b2b814885e5d0f9596c.Components.Settings
@using sv_2799ab90e6164b2b814885e5d0f9596c.Services
@inject ISettingsService SettingsService

<div class="appearance-section">
    <h4>Appearance Settings</h4>
    <hr />

    @if (loading)
    {
        <div class="text-center py-4">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-md-7">
                <div class="mb-4">
                    <h6 class="fw-semibold mb-3">Theme</h6>
                    @foreach (var t in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{t}")" value="@t"
                                   checked="@(theme == t)"
                                   @onchange="() => theme = t" />
                            <label class="form-check-label" for="@($"theme-{t}")">@t</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h6 class="fw-semibold mb-3">Font Size</h6>
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check form-check-inline">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"font-{size}")" value="@size"
                                   checked="@(fontSize == size)"
                                   @onchange="() => fontSize = size" />
                            <label class="form-check-label" for="@($"font-{size}")">@size</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h6 class="fw-semibold mb-3">Language</h6>
                    <select class="form-select" style="max-width: 250px;" @bind="language">
                        <option value="en">English</option>
                        <option value="es">Español</option>
                        <option value="fr">Français</option>
                        <option value="de">Deutsch</option>
                        <option value="ja">日本語</option>
                        <option value="zh">中文</option>
                    </select>
                </div>

                <div class="mb-4">
                    <h6 class="fw-semibold mb-3">Compact Mode</h6>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch"
                               id="compactMode" @bind="compactMode" />
                        <label class="form-check-label" for="compactMode">
                            Reduce spacing and padding throughout the interface
                        </label>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@saving">
                    @if (saving)
                    {
                        <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                    }
                    Save
                </button>

                @if (showSuccess)
                {
                    <div class="alert alert-success mt-3 d-flex align-items-center" role="alert">
                        <span class="me-2">✅</span> Appearance settings saved!
                    </div>
                }

                @if (errorMessage is not null)
                {
                    <div class="alert alert-danger mt-3" role="alert">@errorMessage</div>
                }
            </div>

            <div class="col-md-5">
                <h6 class="fw-semibold mb-3">Live Preview</h6>
                <AppearancePreview Theme="@theme" FontSize="@fontSize" CompactMode="@compactMode" />
            </div>
        </div>
    }
</div>

@code {
    private bool loading = true;
    private bool saving;
    private bool showSuccess;
    private string? errorMessage;

    private string theme = "Light";
    private string fontSize = "Medium";
    private string language = "en";
    private bool compactMode;

    protected override async Task OnInitializedAsync()
    {
        loading = true;
        try
        {
            var settings = await SettingsService.GetAppearanceAsync();
            theme = settings.Theme;
            fontSize = settings.FontSize;
            language = settings.Language;
            compactMode = settings.CompactMode;
        }
        finally
        {
            loading = false;
        }
    }

    private async Task SaveAsync()
    {
        saving = true;
        showSuccess = false;
        errorMessage = null;
        try
        {
            var settings = new AppearanceSettings(theme, fontSize, language, compactMode);
            await SettingsService.SaveAppearanceAsync(settings);
            showSuccess = true;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to save appearance settings: {ex.Message}";
        }
        finally
        {
            saving = false;
        }
    }
}
"}

