@namespace sv_2799ab90e6164b2b814885e5d0f9596c.Components.Settings
@using sv_2799ab90e6164b2b814885e5d0f9596c.Services
@inject ISettingsService SettingsService

<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center"
         style="cursor: pointer;" @onclick="() => expanded = !expanded">
        <h6 class="mb-0 fw-semibold">🔑 Change Password</h6>
        <span class="expand-icon">@(expanded ? "▲" : "▼")</span>
    </div>

    @if (expanded)
    {
        <div class="card-body">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="confirmPassword" />
            </div>

            @if (validationError is not null)
            {
                <div class="alert alert-warning py-2" role="alert">@validationError</div>
            }

            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@updating">
                @if (updating)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Update Password
            </button>

            @if (showSuccess)
            {
                <div class="alert alert-success mt-3 py-2" role="alert">
                    ✅ Password updated successfully!
                </div>
            }

            @if (errorMessage is not null)
            {
                <div class="alert alert-danger mt-3 py-2" role="alert">@errorMessage</div>
            }
        </div>
    }
</div>

@code {
    private bool expanded;
    private bool updating;
    private bool showSuccess;
    private string? validationError;
    private string? errorMessage;

    private string currentPassword = "";
    private string newPassword = "";
    private string confirmPassword = "";

    private async Task UpdatePasswordAsync()
    {
        validationError = null;
        errorMessage = null;
        showSuccess = false;

        if (string.IsNullOrWhiteSpace(currentPassword))
        {
            validationError = "Current password is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(newPassword))
        {
            validationError = "New password is required.";
            return;
        }
        if (newPassword != confirmPassword)
        {
            validationError = "New password and confirmation do not match.";
            return;
        }

        updating = true;
        try
        {
            await SettingsService.ChangePasswordAsync(currentPassword, newPassword);
            showSuccess = true;
            currentPassword = "";
            newPassword = "";
            confirmPassword = "";
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to change password: {ex.Message}";
        }
        finally
        {
            updating = false;
        }
    }
}

