@namespace sv_2799ab90e6164b2b814885e5d0f9596c.Components.Settings
@using sv_2799ab90e6164b2b814885e5d0f9596c.Services

<div class="mb-4">
    <h6 class="fw-semibold mb-3">Active Sessions</h6>

    @if (Sessions.Count == 0)
    {
        <p class="text-muted">No active sessions.</p>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-hover align-middle">
                <thead class="table-light">
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th class="text-end">Action</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@session.LastActive.ToString("g")</td>
                            <td class="text-end">
                                @if (session == Sessions.FirstOrDefault())
                                {
                                    <span class="badge bg-success">Current</span>
                                }
                                else if (confirmingSessionId == session.Id)
                                {
                                    <span class="me-2 text-danger small">Revoke this session?</span>
                                    <button class="btn btn-danger btn-sm me-1"
                                            @onclick="() => ConfirmRevokeAsync(session.Id)"
                                            disabled="@revoking">
                                        @if (revoking)
                                        {
                                            <span class="spinner-border spinner-border-sm" role="status"></span>
                                        }
                                        else
                                        {
                                            <text>Yes</text>
                                        }
                                    </button>
                                    <button class="btn btn-outline-secondary btn-sm"
                                            @onclick="() => confirmingSessionId = null">
                                        No
                                    </button>
                                }
                                else
                                {
                                    <button class="btn btn-outline-danger btn-sm"
                                            @onclick="() => confirmingSessionId = session.Id">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }

    @if (errorMessage is not null)
    {
        <div class="alert alert-danger py-2" role="alert">@errorMessage</div>
    }
</div>

@code {
    [Parameter, EditorRequired] public List<ActiveSession> Sessions { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<string> OnSessionRevoked { get; set; }

    private string? confirmingSessionId;
    private bool revoking;
    private string? errorMessage;

    private async Task ConfirmRevokeAsync(string sessionId)
    {
        revoking = true;
        errorMessage = null;
        try
        {
            await OnSessionRevoked.InvokeAsync(sessionId);
            confirmingSessionId = null;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to revoke session: {ex.Message}";
        }
        finally
        {
            revoking = false;
        }
    }
}

