@namespace sv_2799ab90e6164b2b814885e5d0f9596c.Components.Settings
@using sv_2799ab90e6164b2b814885e5d0f9596c.Services
@inject ISettingsService SettingsService

<div class="security-section">
    <h4>Security Settings</h4>
    <hr />

    @if (loading)
    {
        <div class="text-center py-4">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <ChangePasswordPanel />

        <div class="card mb-4">
            <div class="card-body">
                <div class="d-flex justify-content-between align-items-center">
                    <div>
                        <h6 class="fw-semibold mb-1">Two-Factor Authentication</h6>
                        <p class="text-muted mb-0 small">
                            Add an extra layer of security to your account.
                        </p>
                    </div>
                    <div class="d-flex align-items-center gap-2">
                        <span class="badge @(twoFactorEnabled ? "bg-success" : "bg-secondary")">
                            @(twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                        <div class="form-check form-switch mb-0">
                            <input class="form-check-input" type="checkbox" role="switch"
                                   id="twoFactor" @bind="twoFactorEnabled" />
                        </div>
                    </div>
                </div>
            </div>
        </div>

        @if (lastPasswordChange.HasValue)
        {
            <p class="text-muted small mb-4">
                🕒 Last password change: @lastPasswordChange.Value.ToString("f")
            </p>
        }

        <ActiveSessionsTable Sessions="sessions" OnSessionRevoked="RevokeSessionAsync" />
    }
</div>

@code {
    private bool loading = true;
    private bool twoFactorEnabled;
    private DateTime? lastPasswordChange;
    private List<ActiveSession> sessions = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        loading = true;
        try
        {
            var settings = await SettingsService.GetSecuritySettingsAsync();
            twoFactorEnabled = settings.TwoFactorEnabled;
            lastPasswordChange = settings.LastPasswordChange;
            sessions = settings.Sessions ?? new();
        }
        finally
        {
            loading = false;
        }
    }

    private async Task RevokeSessionAsync(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        sessions.RemoveAll(s => s.Id == sessionId);
    }
}

