@namespace sv_2799ab90e6164b2b814885e5d0f9596c.Components.Settings

<div class="preview-container @ThemeClass @FontSizeClass @CompactClass">
    <div class="preview-header">
        <strong>Preview</strong>
    </div>
    <div class="preview-body">
        <div class="preview-nav">
            <span class="preview-nav-item active">Dashboard</span>
            <span class="preview-nav-item">Settings</span>
            <span class="preview-nav-item">Help</span>
        </div>
        <div class="preview-content">
            <h6 class="preview-title">Welcome back!</h6>
            <p class="preview-text">This is how your application will look with the current settings.</p>
            <button class="preview-button">Sample Button</button>
        </div>
    </div>
</div>

@code {
    [Parameter] public string Theme { get; set; } = "Light";
    [Parameter] public string FontSize { get; set; } = "Medium";
    [Parameter] public bool CompactMode { get; set; }

    private string ThemeClass => Theme switch
    {
        "Dark" => "preview-dark",
        "System" => "preview-system",
        _ => "preview-light"
    };

    private string FontSizeClass => FontSize switch
    {
        "Small" => "preview-font-sm",
        "Large" => "preview-font-lg",
        _ => "preview-font-md"
    };

    private string CompactClass => CompactMode ? "preview-compact" : "";
}

.preview-container {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
    font-size: 0.9rem;
    transition: all 0.2s ease;
}

/* Theme variants */
.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-dark {
    background: #1e1e2e;
    color: #cdd6f4;
}

.preview-system {
    background: #f0f0f5;
    color: #333;
}

/* Font sizes */
.preview-font-sm { font-size: 0.8rem; }
.preview-font-md { font-size: 0.9rem; }
.preview-font-lg { font-size: 1.05rem; }

/* Compact */
.preview-compact .preview-body { padding: 0.5rem; }
.preview-compact .preview-nav { padding: 0.25rem 0.5rem; gap: 0.5rem; }
.preview-compact .preview-content { padding: 0.5rem; }

.preview-header {
    padding: 0.5rem 0.75rem;
    border-bottom: 1px solid rgba(128,128,128,0.2);
    font-size: 0.75rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    opacity: 0.7;
}

.preview-body {
    padding: 0.75rem;
}

.preview-nav {
    display: flex;
    gap: 0.75rem;
    padding: 0.5rem 0.75rem;
    border-bottom: 1px solid rgba(128,128,128,0.15);
    margin-bottom: 0.75rem;
}

.preview-nav-item {
    font-size: 0.8em;
    opacity: 0.6;
    cursor: default;
}

.preview-nav-item.active {
    opacity: 1;
    font-weight: 600;
}

.preview-dark .preview-nav-item.active {
    color: #89b4fa;
}

.preview-content {
    padding: 0.5rem 0.75rem;
}

.preview-title {
    margin-bottom: 0.5rem;
}

.preview-text {
    opacity: 0.7;
    margin-bottom: 0.75rem;
}

.preview-button {
    padding: 0.35rem 0.75rem;
    border-radius: 4px;
    border: none;
    font-size: 0.85em;
    cursor: default;
}

.preview-light .preview-button {
    background: #0d6efd;
    color: white;
}

.preview-dark .preview-button {
    background: #89b4fa;
    color: #1e1e2e;
}

.preview-system .preview-button {
    background: #6366f1;
    color: white;
}

