+<div class="appearance-section">
+    <h4>Appearance Settings</h4>
+    <hr />
+
+    @if (loading)
+    {
+        <div class="text-center py-4">
+            <div class="spinner-border text-primary" role="status">
+                <span class="visually-hidden">Loading...</span>
+            </div>
+        </div>
+    }
+    else
+    {
+        <div class="row">
+            <div class="col-md-7">
+                <div class="mb-4">
+                    <h6 class="fw-semibold mb-3">Theme</h6>
+                    @foreach (var t in new[] { "Light", "Dark", "System" })
+                    {
+                        <div class="form-check mb-2">
+                            <input class="form-check-input" type="radio" name="theme"
+                                   id="@($"theme-{t}")" value="@t"
+                                   checked="@(theme == t)"
+                                   @onchange="() => theme = t" />
+                            <label class="form-check-label" for="@($"theme-{t}")">@t</label>
+                        </div>
+                    }
+                </div>
+
+                <div class="mb-4">
+                    <h6 class="fw-semibold mb-3">Font Size</h6>
+                    @foreach (var size in new[] { "Small", "Medium", "Large" })
+                    {
+                        <div class="form-check form-check-inline">
+                            <input class="form-check-input" type="radio" name="fontSize"
+                                   id="@($"font-{size}")" value="@size"
+                                   checked="@(fontSize == size)"
+                                   @onchange="() => fontSize = size" />
+                            <label class="form-check-label" for="@($"font-{size}")">@size</label>
+                        </div>
+                    }
+                </div>
+
+                <div class="mb-4">
+                    <h6 class="fw-semibold mb-3">Language</h6>
+                    <select class="form-select" style="max-width: 250px;" @bind="language">
+                        <option value="en">English</option>
+                        <option value="es">Español</option>
+                        <option value="fr">Français</option>
+                        <option value="de">Deutsch</option>
+                        <option value="ja">日本語</option>
+                        <option value="zh">中文</option>
+                    </select>
+                </div>
+
+                <div class="mb-4">
