@page "/settings"
@using sv_2799ab90e6164b2b814885e5d0f9596c.Components.Settings
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <SettingsSidebar ActiveSection="@activeSection" OnSectionChanged="section => activeSection = section" />

    <div class="settings-content">
        @switch (activeSection)
        {
            case "profile":
                <ProfileSection />
                break;
            case "notifications":
                <NotificationsSection />
                break;
            case "security":
                <SecuritySection />
                break;
            case "appearance":
                <AppearanceSection />
                break;
        }
    </div>
</div>

@code {
    private string activeSection = "profile";
}

.settings-dashboard {
    display: flex;
    min-height: calc(100vh - 100px);
    margin: -1rem -1.5rem;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
    background: #fff;
}

.settings-content {
    flex: 1;
    padding: 2rem;
    overflow-y: auto;
}

